```javascript
// tailwind.config.js
/** @type {import('tailwindcss').Config} */
export default {
  darkMode: 'class',  // 'media' pour la préférence système, 'class' pour le basculement manuel
  content: ['./index.html', './src/**/*.{js,ts,jsx,tsx}'],
  theme: { extend: {} },
  plugins: [],
}
```
Avec `darkMode: 'class'`, Tailwind applique les classes `dark:` uniquement lorsque l'élément parent (généralement `<html>`) porte la classe `dark`.

```jsx
// ThemeToggle.jsx
import { useState, useEffect } from 'react';

export default function ThemeToggle() {
  const [darkMode, setDarkMode] = useState(false);

  // Charger la préférence au montage
  useEffect(() => {
    const savedTheme = localStorage.getItem('theme');
    if (savedTheme === 'dark') {
      setDarkMode(true);
      document.documentElement.classList.add('dark');
    } else if (savedTheme === 'light') {
      setDarkMode(false);
      document.documentElement.classList.remove('dark');
    }
  }, []);

  const toggleTheme = () => {
    const newDarkMode = !darkMode;
    setDarkMode(newDarkMode);

    if (newDarkMode) {
      document.documentElement.classList.add('dark');
      localStorage.setItem('theme', 'dark');
    } else {
      document.documentElement.classList.remove('dark');
      localStorage.setItem('theme', 'light');
    }
  };

  return (
    <button
      onClick={toggleTheme}
      className="p-2 rounded-lg bg-gray-200 dark:bg-gray-700"
    >
      {darkMode ? '☀️ Mode clair' : '🌙 Mode sombre'}
    </button>
  );
}
```

```jsx
useEffect(() => {
  const savedTheme = localStorage.getItem('theme');

  if (savedTheme === 'dark') {
    setDarkMode(true);
    document.documentElement.classList.add('dark');
  } else if (savedTheme === 'light') {
    setDarkMode(false);
    document.documentElement.classList.remove('dark');
  } else {
    // Aucune préférence stockée → détecter la préférence système
    const systemPrefersDark = window.matchMedia('(prefers-color-scheme: dark)').matches;
    setDarkMode(systemPrefersDark);
    if (systemPrefersDark) {
      document.documentElement.classList.add('dark');
    }
    // On peut aussi stocker cette préférence pour les prochaines fois
    localStorage.setItem('theme', systemPrefersDark ? 'dark' : 'light');
  }
}, []);
```
`window.matchMedia('(prefers-color-scheme: dark)').matches` retourne `true` si l'OS est en mode sombre.

```javascript
// stores/themeStore.js
import { create } from 'zustand';
import { persist } from 'zustand/middleware';

export const useThemeStore = create(
  persist(
    (set) => ({
      theme: 'light', // 'light' ou 'dark'
      setTheme: (newTheme) => {
        set({ theme: newTheme });
        // Appliquer la classe sur l'élément html
        if (newTheme === 'dark') {
          document.documentElement.classList.add('dark');
        } else {
          document.documentElement.classList.remove('dark');
        }
      },
      toggleTheme: () => set((state) => {
        const newTheme = state.theme === 'light' ? 'dark' : 'light';
        if (newTheme === 'dark') {
          document.documentElement.classList.add('dark');
        } else {
          document.documentElement.classList.remove('dark');
        }
        return { theme: newTheme };
      }),
      // Détecter la préférence système au démarrage
      initTheme: () => {
        const systemPrefersDark = window.matchMedia('(prefers-color-scheme: dark)').matches;
        const initialTheme = systemPrefersDark ? 'dark' : 'light';
        set({ theme: initialTheme });
        if (initialTheme === 'dark') {
          document.documentElement.classList.add('dark');
        }
      }
    }),
    {
      name: 'theme-storage', // clé dans localStorage
    }
  )
);
```

**Utilisation dans un composant :**
```jsx
const { theme, toggleTheme } = useThemeStore();
<button onClick={toggleTheme}>
  {theme === 'light' ? '🌙' : '☀️'}
</button>
```

