// Dans le composant principal (App.jsx ou Layout)
useEffect(() => {
  // Vérifier si l'utilisateur a déjà fait un choix manuel
  const hasManualChoice = localStorage.getItem('theme') !== null;

  if (hasManualChoice) return;

  const mediaQuery = window.matchMedia('(prefers-color-scheme: dark)');

  const handleSystemThemeChange = (e) => {
    const newTheme = e.matches ? 'dark' : 'light';
    if (newTheme === 'dark') {
      document.documentElement.classList.add('dark');
    } else {
      document.documentElement.classList.remove('dark');
    }
    // Optionnel : mettre à jour le store Zustand sans persister
    // useThemeStore.setState({ theme: newTheme });
  };

  mediaQuery.addEventListener('change', handleSystemThemeChange);

  return () => mediaQuery.removeEventListener('change', handleSystemThemeChange);
}, []);
```

**Avec Zustand et persistance conditionnelle :**
```javascript
// Variante plus avancée
const mediaQuery = window.matchMedia('(prefers-color-scheme: dark)');
mediaQuery.addEventListener('change', (e) => {
  const hasManualChoice = localStorage.getItem('theme-storage') !== null;
  if (!hasManualChoice) {
    const newTheme = e.matches ? 'dark' : 'light';
    useThemeStore.getState().setTheme(newTheme);
  }
});
```

**Solution :** Ajouter un script inline dans `<head>` qui s'exécute avant le rendu du DOM.

```html
<!-- index.html -->
<!DOCTYPE html>
<html lang="fr">
<head>
  <script>
    // Récupérer le thème stocké ou la préférence système
    const getInitialTheme = () => {
      const stored = localStorage.getItem('theme');
      if (stored === 'dark') return 'dark';
      if (stored === 'light') return 'light';
      return window.matchMedia('(prefers-color-scheme: dark)').matches ? 'dark' : 'light';
    };

    const theme = getInitialTheme();
    if (theme === 'dark') {
      document.documentElement.classList.add('dark');
    }
  </script>
  <meta charset="UTF-8" />
  <link rel="icon" type="image/svg+xml" href="/vite.svg" />
  <meta name="viewport" content="width=device-width, initial-scale=1.0" />
  <title>E-commerce App</title>
</head>
<body>
  <div id="root"></div>
  <script type="module" src="/src/main.jsx"></script>
</body>
</html>
```

**Explication :** Ce script s'exécute immédiatement, avant que React ne charge et n'affiche le contenu. La classe `dark` est donc déjà présente sur `<html>` lorsque le CSS Tailwind est appliqué, éliminant tout flash.
